"use client";

import { type CommandPaletteProps, CommandPalette as CommandPaletteRoot } from "./command-palette";
import {
  CommandPaletteContent,
  type CommandPaletteContentProps,
  type CommandPaletteDensity,
  type CommandPaletteFrame,
  commandPaletteContentVariants,
} from "./command-palette-content";
import { CommandPaletteEmpty, type CommandPaletteEmptyProps } from "./command-palette-empty";
import { CommandPaletteFooter, type CommandPaletteFooterProps } from "./command-palette-footer";
import { CommandPaletteGroup, type CommandPaletteGroupProps } from "./command-palette-group";
import { CommandPaletteInput, type CommandPaletteInputProps } from "./command-palette-input";
import {
  CommandPaletteItem,
  type CommandPaletteItemProps,
  type CommandPaletteItemTone,
} from "./command-palette-item";
import { CommandPaletteList, type CommandPaletteListProps } from "./command-palette-list";

/**
 * Terminal-styled command palette with built-in search filtering, grouped items, and keyboard
 * navigation. Uses native dialog element with backdrop blur. Two orthogonal visual axes on
 * Content (frame and density) keep visual chrome configurable without touching internals.
 */
const CommandPalette = Object.assign(CommandPaletteRoot, {
  Content: CommandPaletteContent,
  Input: CommandPaletteInput,
  List: CommandPaletteList,
  Group: CommandPaletteGroup,
  Item: CommandPaletteItem,
  Empty: CommandPaletteEmpty,
  Footer: CommandPaletteFooter,
});

export { CommandPalette, type CommandPaletteProps };
export {
  CommandPaletteContent,
  commandPaletteContentVariants,
  type CommandPaletteContentProps,
  type CommandPaletteFrame,
  type CommandPaletteDensity,
};
export { CommandPaletteInput, type CommandPaletteInputProps };
export { CommandPaletteList, type CommandPaletteListProps };
export { CommandPaletteGroup, type CommandPaletteGroupProps };
export { CommandPaletteItem, type CommandPaletteItemProps, type CommandPaletteItemTone };
export { CommandPaletteEmpty, type CommandPaletteEmptyProps };
export { CommandPaletteFooter, type CommandPaletteFooterProps };

"use client";

import type { ReactNode } from "react";
import { CommandPaletteContext } from "./command-palette-context";
import { type UseCommandPaletteStateOptions, useCommandPaletteState } from "./use-state";

/** Props for command palette. */
export interface CommandPaletteProps extends UseCommandPaletteStateOptions {
  /** Content rendered inside the component. */
  children: ReactNode;
}

/**
 * Terminal-styled command palette with built-in search filtering, grouped items, and keyboard
 * navigation. Uses native dialog element with backdrop blur. Two orthogonal visual axes on
 * Content (frame and density) keep visual chrome configurable without touching internals.
 */
export function CommandPalette({ children, ...stateProps }: CommandPaletteProps) {
  const contextValue = useCommandPaletteState(stateProps);

  return <CommandPaletteContext value={contextValue}>{children}</CommandPaletteContext>;
}

"use client";

import { createContext, useContext } from "react";
import type { CommandPaletteContextValue } from "./use-state";

export type { CommandPaletteContextValue } from "./use-state";

/** React context backing command palette. */
export const CommandPaletteContext = createContext<CommandPaletteContextValue | undefined>(
  undefined,
);

/** Reads the command palette context. */
export function useCommandPaletteContext() {
  const context = useContext(CommandPaletteContext);
  if (!context)
    throw new Error("CommandPalette compound components must be used within a CommandPalette");
  return context;
}

"use client";

import { cva, type VariantProps } from "class-variance-authority";
import { type ReactNode, useCallback, useState } from "react";
import { useFocusRestore } from "@/hooks/use-focus-restore";
import { cn } from "@/lib/utils";
import { DialogShell } from "../shared/dialog-shell";
import { PortalContainerProvider } from "../shared/portal-context";
import { useCommandPaletteContext } from "./command-palette-context";

/** Allowed command palette frame values. */
export type CommandPaletteFrame = "border" | "viewfinder" | "terminal" | "card" | "none";
/** Allowed command palette density values. */
export type CommandPaletteDensity = "compact" | "comfortable" | "dense";

/** Class variants for command palette content. */
export const commandPaletteContentVariants = cva(
  "relative flex flex-col max-h-[80vh] m-auto w-full font-mono",
  {
    variants: {
      size: { sm: "max-w-sm", md: "max-w-xl", lg: "max-w-2xl" },
    },
    defaultVariants: { size: "md" },
  },
);

function getLiveText(search: string, itemCount: number): string {
  if (!search) return "";
  if (itemCount === 0) return "No results";
  return `${itemCount} result${itemCount === 1 ? "" : "s"} available`;
}

/** Props for command palette content. */
export interface CommandPaletteContentProps
  extends VariantProps<typeof commandPaletteContentVariants> {
  /** Content rendered inside the component. */
  children: ReactNode;
  /** Additional class names merged onto the rendered element. */
  className?: string;
  /** Accessible name for the modal dialog. */
  label?: string;
  /**
   * Shell chrome style. "border" renders a 1px hairline. "viewfinder" renders four corner
   * brackets with no border plus a 2px left accent bar on the selected row. "terminal" renders
   * top + bottom 2px rules with inverted selection and swaps the default prefix glyph from > to
   * $. "card" renders an 8px rounded shell with a subtle gradient surface and a floating
   * rounded selection (compose with a search-icon `prefix` for the Linear look). "none" is a
   * bare shell for embedding.
   */
  frame?: CommandPaletteFrame | null;
  /**
   * Typographic and spacing surface. Switches a token block (--command-palette-row-h,
   * --command-palette-input-py, --command-palette-list-p, --command-palette-text-size, etc.)
   * consumed by every inner slot via [data-density] selectors in
   * command-palette/command-palette.css. "compact" matches the V1 refined-mono target,
   * "comfortable" is Linear-ish breathing room, "dense" is VSCode-tight.
   */
  density?: CommandPaletteDensity | null;
}

/** Native dialog modal container with frame + density variants. */
export function CommandPaletteContent({
  children,
  className,
  size,
  frame,
  density,
  label = "Command palette",
}: CommandPaletteContentProps) {
  const { open, onOpenChange, search, onSearchChange, itemCount, inputRef } =
    useCommandPaletteContext();
  const [container, setContainer] = useState<Element | null>(null);
  const focusRestore = useFocusRestore({ restoreOnUnmount: false });

  const resolvedFrame = frame ?? "border";
  const resolvedDensity = density ?? "compact";

  // Stable identity for DialogShell's dialogRef callback so the underlying ref isn't re-attached on every render.
  const setDialogRef = useCallback((node: HTMLDialogElement | null) => {
    setContainer(node);
  }, []);

  // Stable identity for DialogShell's onAfterShowModal so focus runs only on open transitions.
  const focusSearchInput = useCallback(() => {
    inputRef.current?.focus();
  }, [inputRef]);

  return (
    <DialogShell
      open={open}
      dialogRef={setDialogRef}
      onBeforeShowModal={focusRestore.capture}
      onAfterShowModal={focusSearchInput}
      onBackdropClick={() => onOpenChange(false)}
      onCancel={() => (search ? onSearchChange("") : onOpenChange(false))}
      onClose={focusRestore.restore}
      className={cn(commandPaletteContentVariants({ size }), className)}
      data-slot="command-palette-content"
      data-frame={resolvedFrame}
      data-density={resolvedDensity}
      aria-modal="true"
      aria-label={label}
    >
      <PortalContainerProvider container={container}>
        {resolvedFrame === "viewfinder" ? <span aria-hidden="true" className="cp-corners" /> : null}
        {children}
        {/* biome-ignore lint/a11y/useSemanticElements: role="status" is the sr-only results-count live region; <output> carries form-association semantics that do not fit here. */}
        <div role="status" aria-live="polite" aria-atomic="true" className="sr-only">
          {getLiveText(search, itemCount)}
        </div>
      </PortalContainerProvider>
    </DialogShell>
  );
}

"use client";

import type { KeyboardEvent as ReactKeyboardEvent, ReactNode, Ref } from "react";
import { Kbd } from "@/components/ui/kbd";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { cn } from "@/lib/utils";
import { useCommandPaletteContext } from "./command-palette-context";
import { getCommandPaletteItemDomId } from "./use-state";

const INPUT_NAVIGATION_KEYS = new Set(["ArrowUp", "ArrowDown", "Enter"]);

/** Props for command palette input. */
export interface CommandPaletteInputProps {
  /** Search input placeholder. */
  placeholder?: string;
  /** Accessible label text. */
  label?: string;
  /**
   * Optional leading content. When omitted, a CSS-driven glyph from
   * --command-palette-prefix-content is rendered (default ">"; terminal frame swaps to "$").
   */
  prefix?: ReactNode;
  /** Optional trailing content. Defaults to a Kbd "Esc" hint. */
  suffix?: ReactNode;
  /** Called when key down occurs. */
  onKeyDown?: (event: ReactKeyboardEvent<HTMLInputElement>) => void;
  /** Additional class names merged onto the rendered element. */
  className?: string;
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLInputElement>;
}

/** Search input with prefix/suffix slots (Esc Kbd by default) */
export function CommandPaletteInput({
  placeholder = "Type a command…",
  label = "Command search",
  prefix,
  suffix,
  onKeyDown,
  className,
  ref,
}: CommandPaletteInputProps) {
  const { open, search, onSearchChange, navKeyDown, highlighted, listId, inputRef } =
    useCommandPaletteContext();
  const composedRef = useComposedRefs(inputRef, ref);

  return (
    <div data-slot="command-palette-input" className={cn(className)}>
      {prefix !== undefined ? (
        <span data-slot="command-palette-input-prefix">{prefix}</span>
      ) : (
        <span data-slot="command-palette-input-prefix" data-default aria-hidden="true" />
      )}
      <input
        ref={composedRef}
        type="text"
        role="combobox"
        aria-label={label}
        aria-expanded={open}
        aria-autocomplete="list"
        aria-controls={listId}
        aria-activedescendant={
          highlighted !== null ? getCommandPaletteItemDomId(listId, highlighted) : undefined
        }
        value={search}
        onChange={(e) => onSearchChange(e.target.value)}
        onKeyDown={(e) => {
          onKeyDown?.(e);
          if (e.defaultPrevented) return;
          if (e.key === "Escape") {
            if (search) {
              e.preventDefault();
              onSearchChange("");
            }
            return;
          }
          if (e.key === " ") return;
          if (INPUT_NAVIGATION_KEYS.has(e.key)) navKeyDown(e);
        }}
        placeholder={placeholder}
        className="flex-1 min-w-0 bg-transparent border-0 outline-none p-0 text-foreground placeholder-muted-foreground/70 font-mono caret-foreground"
        style={{ fontSize: "var(--command-palette-text-size)" }}
      />
      {suffix !== undefined ? (
        <span data-slot="command-palette-input-suffix">{suffix}</span>
      ) : (
        <span data-slot="command-palette-input-suffix">
          <Kbd size="sm">Esc</Kbd>
        </span>
      )}
    </div>
  );
}

"use client";

import type { ReactNode, Ref } from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { cn } from "@/lib/utils";
import { useCommandPaletteContext } from "./command-palette-context";

/** Props for command palette list. */
export interface CommandPaletteListProps {
  /** Content rendered inside the component. */
  children: ReactNode;
  /** Additional class names merged onto the rendered element. */
  className?: string;
  /** Accessible name when no visible label is supplied. */
  "aria-label"?: string;
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLDivElement>;
}

/** Scrollable item container. */
export function CommandPaletteList({
  children,
  className,
  "aria-label": ariaLabel = "Command results",
  ref,
}: CommandPaletteListProps) {
  const { listRef, listId } = useCommandPaletteContext();
  const composedRef = useComposedRefs(listRef, ref);
  return (
    <div
      id={listId}
      ref={composedRef}
      role="listbox"
      aria-label={ariaLabel}
      data-slot="command-palette-list"
      className={cn("flex-1 overflow-y-auto", className)}
    >
      {children}
    </div>
  );
}

"use client";

import { type ReactNode, useId } from "react";
import { cn } from "@/lib/utils";

/** Props for command palette group. */
export interface CommandPaletteGroupProps {
  /** Group heading rendered above the items. */
  heading: ReactNode;
  /** Content rendered inside the component. */
  children: ReactNode;
  /** Additional class names merged onto the rendered element. */
  className?: string;
}

/** Labeled group of items. */
export function CommandPaletteGroup({ heading, children, className }: CommandPaletteGroupProps) {
  const headingId = useId();
  return (
    // biome-ignore lint/a11y/useSemanticElements: role="group" labels a related set of command options; <fieldset> is for form controls and is not appropriate here.
    <div
      role="group"
      aria-labelledby={headingId}
      data-slot="command-palette-group"
      className={cn("hidden has-[[role=option]]:block", className)}
    >
      <div id={headingId} data-slot="command-palette-group-heading">
        {heading}
      </div>
      <div>{children}</div>
    </div>
  );
}

"use client";

import type { ReactNode } from "react";
import { useCommandPaletteContext } from "./command-palette-context";

/** Props for command palette empty. */
export interface CommandPaletteEmptyProps {
  /** Content rendered inside the component. */
  children: ReactNode;
  /** Additional class names merged onto the rendered element. */
  className?: string;
}

/** Shown when no items match search. */
export function CommandPaletteEmpty({ children, className }: CommandPaletteEmptyProps) {
  const { itemCount, search } = useCommandPaletteContext();
  if (itemCount > 0 || !search) return null;
  return (
    // The no-results announcement is owned by CommandPaletteContent's single live
    // region; this presentational node is just the visible empty-state copy and
    // must not be an invalid live-region child of the listbox.
    <div role="presentation" data-slot="command-palette-empty" className={className}>
      {children}
    </div>
  );
}

