"use client";

import {
  type ComponentPropsWithRef,
  type MouseEvent,
  type ReactNode,
  useId,
  useLayoutEffect,
  useRef,
} from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { useCommandPaletteContext } from "./command-palette-context";
import { getCommandPaletteItemDomId } from "./use-state";

/** Allowed command palette item tone values. */
export type CommandPaletteItemTone =
  | "neutral"
  | "nav"
  | "action"
  | "settings"
  | "destructive"
  | "ai";

/** Props for command palette item. */
export interface CommandPaletteItemProps
  extends Omit<ComponentPropsWithRef<"div">, "children" | "id" | "onSelect"> {
  /** Stable unique id used for highlight state and aria-activedescendant. */
  id: string;
  /** Searchable text. Defaults to id when omitted. */
  value?: string;
  /** Optional leading icon. Inherits tone color when a non-neutral tone is set. */
  icon?: ReactNode;
  /** Keyboard shortcut hint rendered next to the label. */
  shortcut?: string;
  /**
   * Semantic tone. Renders a 2px left bar and tints the optional icon via [data-tone]
   * selectors. The label color stays inherited so contrast holds under any frame. Map:
   * nav→info, action→success, settings→warning, destructive→destructive, ai→accent.
   */
  tone?: CommandPaletteItemTone;
  /** Called when the item is activated. Runs before CommandPalette.onActivate. */
  onSelect?: () => void;
  /** Disable activation and skip in keyboard navigation. */
  disabled?: boolean;
  /** Content rendered inside the component. */
  children: ReactNode;
}

/** Selectable item with icon, shortcut, tone, value. */
export function CommandPaletteItem({
  id,
  value,
  icon,
  shortcut,
  tone = "neutral",
  onSelect,
  disabled = false,
  children,
  className,
  ref,
  onClick,
  onMouseMove,
  ...props
}: CommandPaletteItemProps) {
  const {
    highlighted,
    onHighlightChange,
    onActivate,
    search,
    shouldFilter,
    filter,
    listId,
    registerItem,
    unregisterItem,
  } = useCommandPaletteContext();
  const registrationId = useId();
  const rootRef = useRef<HTMLDivElement>(null);
  const composedRef = useComposedRefs(rootRef, ref);

  const searchValue = value ?? id;
  const isVisible = !shouldFilter || !search || filter(searchValue, search);

  useLayoutEffect(() => {
    registerItem({
      registrationId,
      id,
      value: searchValue,
      disabled: disabled || !isVisible,
      onSelect: disabled ? undefined : onSelect,
      element: isVisible ? rootRef.current : null,
    });
    return () => unregisterItem(registrationId);
  }, [
    disabled,
    id,
    isVisible,
    onSelect,
    registerItem,
    registrationId,
    searchValue,
    unregisterItem,
  ]);

  if (!isVisible) return null;

  const isHighlighted = highlighted === id;

  const handleClick = (event: MouseEvent<HTMLDivElement>) => {
    onClick?.(event);
    if (!event.defaultPrevented && !disabled) onActivate(id);
  };

  const handleMouseMove = (event: MouseEvent<HTMLDivElement>) => {
    onMouseMove?.(event);
    if (event.defaultPrevented || disabled) return;
    if (highlighted !== id) onHighlightChange(id);
  };

  return (
    // biome-ignore lint/a11y/useFocusableInteractive: WAI-ARIA combobox/listbox pattern — option stays non-focusable while the input keeps focus and aria-activedescendant tracks the active option.
    // biome-ignore lint/a11y/useKeyWithClickEvents: Enter activation is handled centrally by the command palette input, not per option.
    <div
      {...props}
      ref={composedRef}
      id={getCommandPaletteItemDomId(listId, id)}
      role="option"
      data-slot="command-palette-item"
      data-value={id}
      data-tone={tone}
      aria-selected={isHighlighted}
      aria-disabled={disabled || undefined}
      onClick={handleClick}
      onMouseMove={handleMouseMove}
      className={className}
    >
      {icon !== undefined && <span data-slot="command-palette-item-icon">{icon}</span>}
      <span data-slot="command-palette-item-label">{children}</span>
      {shortcut ? <span data-slot="command-palette-item-shortcut">{shortcut}</span> : null}
    </div>
  );
}

"use client";

import { Children, type ReactNode } from "react";
import { useCommandPaletteContext } from "./command-palette-context";
import {
  CommandPaletteItem,
  type CommandPaletteItemProps,
  type CommandPaletteItemTone,
} from "./command-palette-item";

const TONE_RULES: ReadonlyArray<readonly [RegExp, CommandPaletteItemTone]> = [
  [/^(delete|remove|reset|drop|destroy|log\s*out|sign\s*out)\b/i, "destructive"],
  [/^(go to|open|jump|navigate|switch|view)\b/i, "nav"],
  [/^(toggle|enable|disable|set|configure|preferences|settings)\b/i, "settings"],
  [/^(ask|generate|summari[sz]e|explain|chat|ai)\b/i, "ai"],
  [/^(run|exec|build|test|deploy|create|new|add|export|import|copy)\b/i, "action"],
];

/** categorize utility. */
export function categorize(value: string): CommandPaletteItemTone {
  const trimmed = value.trim();
  for (const [pattern, tone] of TONE_RULES) {
    if (pattern.test(trimmed)) return tone;
  }
  return "neutral";
}

/** match positions utility. */
export function matchPositions(value: string, search: string): number[] {
  if (!search) return [];
  const lowerValue = value.toLowerCase();
  const lowerSearch = search.toLowerCase();
  const contiguous = lowerValue.indexOf(lowerSearch);
  if (contiguous !== -1) {
    return Array.from({ length: lowerSearch.length }, (_, i) => contiguous + i);
  }
  const positions: number[] = [];
  let cursor = 0;
  for (const char of lowerSearch) {
    const index = lowerValue.indexOf(char, cursor);
    if (index === -1) return [];
    positions.push(index);
    cursor = index + 1;
  }
  return positions;
}

function renderWithMatches(value: string, search: string): ReactNode {
  const positions = matchPositions(value, search);
  if (positions.length === 0) return value;
  const set = new Set(positions);
  const nodes: ReactNode[] = [];
  for (let i = 0; i < value.length; i++) {
    const char = value[i] ?? "";
    if (set.has(i)) {
      nodes.push(
        <mark key={i} data-slot="command-palette-item-match">
          {char}
        </mark>,
      );
    } else {
      nodes.push(char);
    }
  }
  return nodes;
}

function extractText(children: ReactNode): string {
  let text = "";
  Children.forEach(children, (child) => {
    if (typeof child === "string" || typeof child === "number") {
      text += String(child);
    }
  });
  return text;
}

// Children are highlight-safe when extractText recovers the full descendant
// text — i.e. nothing was dropped by skipping non-string nodes. For mixed
// content (icons, <strong>, etc.) we must render children untouched to avoid
// silent content loss.
function isPureText(children: ReactNode): boolean {
  if (typeof children === "string" || typeof children === "number") return true;
  if (Array.isArray(children)) return children.every(isPureText);
  return false;
}

/** Props for command palette highlight item. */
export interface CommandPaletteHighlightItemProps extends Omit<CommandPaletteItemProps, "tone"> {
  /** Visual tone. */
  tone?: CommandPaletteItemTone;
  /** Accessible label text. */
  label?: string;
}

/**
 * Terminal-styled command palette with built-in search filtering, grouped items, and keyboard
 * navigation. Uses native dialog element with backdrop blur. Two orthogonal visual axes on
 * Content (frame and density) keep visual chrome configurable without touching internals.
 */
export function CommandPaletteHighlightItem({
  tone,
  value,
  label,
  children,
  ...rest
}: CommandPaletteHighlightItemProps) {
  const { search } = useCommandPaletteContext();
  const renderedChildren = children ?? label;
  const childrenIsPureText = children !== undefined && isPureText(children);
  const labelText = label ?? (childrenIsPureText ? extractText(children) : "");
  const searchValue = value ?? labelText;
  const resolvedTone = tone ?? categorize(labelText);
  return (
    <CommandPaletteItem {...rest} value={searchValue} tone={resolvedTone}>
      {childrenIsPureText && search
        ? renderWithMatches(extractText(children), search)
        : renderedChildren}
    </CommandPaletteItem>
  );
}

export {
  CommandPaletteHighlightItem,
  type CommandPaletteHighlightItemProps,
  categorize,
  matchPositions,
} from "./command-palette-highlight";

"use client";

import {
  type KeyboardEvent as ReactKeyboardEvent,
  type RefObject,
  useCallback,
  useId,
  useMemo,
  useRef,
  useState,
} from "react";
import { useControllableState } from "@/hooks/use-controllable-state";
import { useNavigation } from "@/hooks/use-navigation";
import { matchesSearch } from "@/lib/search";
import { sortSelectableCollectionItems } from "@/lib/selectable-collection";

/** Context value shared by command palette. */
export interface CommandPaletteContextValue {
  /**
   * Controlled open state. Required to actually show the palette - wire a trigger button or
   * shortcut to setOpen(true).
   */
  open: boolean;
  /** Called whenever open state changes. */
  onOpenChange: (open: boolean) => void;
  /** Controlled highlighted item id. */
  highlighted: string | null;
  /** Called when the highlighted item changes. */
  onHighlightChange: (id: string | null) => void;
  /** Called when an item is activated (Enter or click). Fires after the item's own onSelect. */
  onActivate: (id: string) => void;
  /** Controlled search query. */
  search: string;
  /** Called when the search query changes. */
  onSearchChange: (value: string) => void;
  /** Auto-filter items by search. Pass false to handle filtering yourself (e.g. server-side). */
  shouldFilter: boolean;
  /**
   * Custom filter function. Defaults to case-insensitive substring match on the item's value
   * (or id).
   */
  filter: (value: string, search: string) => boolean;
  /** item count used by command palette. */
  itemCount: number;
  /** DOM id for list. */
  listId: string;
  /** Ref for the list element. */
  listRef: RefObject<HTMLDivElement | null>;
  /** Ref for the input element. */
  inputRef: RefObject<HTMLInputElement | null>;
  /** nav key down used by command palette. */
  navKeyDown: (event: ReactKeyboardEvent) => void;
  /** Registers item with command palette. */
  registerItem: (item: CommandPaletteItemRegistration) => void;
  /** Unregisters item from command palette. */
  unregisterItem: (registrationId: string) => void;
}

const defaultFilter = matchesSearch;

/** Returns command palette item dom id. */
export function getCommandPaletteItemDomId(listId: string, id: string): string {
  const encoded = Array.from(id, (char) => char.codePointAt(0)?.toString(36) ?? "0").join("-");
  return `${listId}-item-${encoded || "empty"}`;
}

/** Options for use command palette state. */
export interface UseCommandPaletteStateOptions {
  /**
   * Controlled open state. Required to actually show the palette - wire a trigger button or
   * shortcut to setOpen(true).
   */
  open?: boolean;
  /** Called whenever open state changes. */
  onOpenChange?: (open: boolean) => void;
  /** Controlled search query. */
  search?: string;
  /** Called when the search query changes. */
  onSearchChange?: (value: string) => void;
  /** Controlled highlighted item id. */
  highlighted?: string | null;
  /** Called when the highlighted item changes. */
  onHighlightChange?: (id: string | null) => void;
  /** Called when an item is activated (Enter or click). Fires after the item's own onSelect. */
  onActivate?: (id: string) => void;
  /** Auto-filter items by search. Pass false to handle filtering yourself (e.g. server-side). */
  shouldFilter?: boolean;
  /**
   * Custom filter function. Defaults to case-insensitive substring match on the item's value
   * (or id).
   */
  filter?: (value: string, search: string) => boolean;
}

/** Provides command palette state behavior. */
export function useCommandPaletteState({
  open: controlledOpen,
  onOpenChange,
  search: controlledSearch,
  onSearchChange: controlledOnSearchChange,
  highlighted: controlledHighlighted,
  onHighlightChange,
  onActivate,
  shouldFilter = true,
  filter: filterProp,
}: UseCommandPaletteStateOptions): CommandPaletteContextValue {
  const [registeredItems, setRegisteredItems] = useState<CommandPaletteItemRegistration[]>([]);
  const filter = filterProp ?? defaultFilter;
  const [isOpen, setIsOpen] = useControllableState({
    value: controlledOpen,
    defaultValue: false,
    onChange: onOpenChange,
  });
  const [search, setSearch] = useControllableState({
    value: controlledSearch,
    defaultValue: "",
    onChange: controlledOnSearchChange,
  });
  const [highlighted, setHighlighted, isHighlightedControlled] = useControllableState<
    string | null
  >({
    value: controlledHighlighted,
    controlled: controlledHighlighted !== undefined,
    defaultValue: null,
    onChange: onHighlightChange,
  });
  const listRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const paletteId = useId();
  const activeItems = useMemo(
    () =>
      sortSelectableCollectionItems(registeredItems).filter(
        (item) => !item.disabled && item.element !== null,
      ),
    [registeredItems],
  );
  const itemCallbacks = useMemo(
    () => new Map(activeItems.map((item) => [item.id, item.onSelect])),
    [activeItems],
  );
  const itemIds = useMemo(() => activeItems.map((item) => item.id), [activeItems]);

  const handleOpenChange = useCallback(
    (next: boolean) => {
      if (!next) setSearch("");
      setIsOpen(next);
    },
    [setIsOpen, setSearch],
  );

  const handleActivate = useCallback(
    (id: string) => {
      itemCallbacks.get(id)?.();
      onActivate?.(id);
      handleOpenChange(false);
    },
    [handleOpenChange, itemCallbacks, onActivate],
  );

  const registerItem = useCallback((item: CommandPaletteItemRegistration) => {
    setRegisteredItems((current) => {
      const existingIndex = current.findIndex(
        (candidate) => candidate.registrationId === item.registrationId,
      );
      const next = existingIndex === -1 ? [...current, item] : [...current];
      if (existingIndex !== -1) next[existingIndex] = item;
      return next;
    });
  }, []);

  const unregisterItem = useCallback((registrationId: string) => {
    setRegisteredItems((current) =>
      current.filter((item) => item.registrationId !== registrationId),
    );
  }, []);

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef: listRef,
    role: "option",
    wrap: true,
    highlighted: getEffectiveHighlighted(highlighted, itemIds, isHighlightedControlled),
    onHighlightChange: setHighlighted,
    onEnter: handleActivate,
    enabled: isOpen,
    scopeToContainer: true,
  });

  return useMemo(
    () => ({
      open: isOpen,
      onOpenChange: handleOpenChange,
      highlighted: getEffectiveHighlighted(highlighted, itemIds, isHighlightedControlled),
      onHighlightChange: setHighlighted,
      onActivate: handleActivate,
      search,
      onSearchChange: setSearch,
      shouldFilter,
      filter,
      itemCount: itemIds.length,
      listId: `${paletteId}-list`,
      listRef,
      inputRef,
      navKeyDown,
      registerItem,
      unregisterItem,
    }),
    [
      isOpen,
      handleOpenChange,
      handleActivate,
      highlighted,
      itemIds,
      isHighlightedControlled,
      setHighlighted,
      search,
      setSearch,
      shouldFilter,
      filter,
      paletteId,
      navKeyDown,
      registerItem,
      unregisterItem,
    ],
  );
}

/** Selectable item with icon, shortcut, tone, value. */
export interface CommandPaletteItemMetadata {
  /** Stable unique id used for highlight state and aria-activedescendant. */
  id: string;
  /** Searchable text. Defaults to id when omitted. */
  value: string;
  /** Disable activation and skip in keyboard navigation. */
  disabled: boolean;
  /** Called when the item is activated. Runs before CommandPalette.onActivate. */
  onSelect?: () => void;
}

/**
 * Terminal-styled command palette with built-in search filtering, grouped items, and keyboard
 * navigation. Uses native dialog element with backdrop blur. Two orthogonal visual axes on
 * Content (frame and density) keep visual chrome configurable without touching internals.
 */
export interface CommandPaletteItemRegistration extends CommandPaletteItemMetadata {
  /** DOM id for registration. */
  registrationId: string;
  /** element used by command palette item registration. */
  element: HTMLElement | null;
}

function getEffectiveHighlighted(
  highlighted: string | null,
  items: readonly string[],
  isControlled: boolean,
): string | null {
  if (highlighted !== null && items.includes(highlighted)) return highlighted;
  if (isControlled) return null;
  return items[0] ?? null;
}

/*
 * CommandPalette primitive styles. Two orthogonal axes drive visual chrome
 * via data-attribute selectors on [data-slot="command-palette-content"]:
 *   [data-frame] = border | viewfinder | terminal | card | none
 *   [data-density] = compact | comfortable | dense
 *
 * Density controls a CSS-variable surface read by every inner slot:
 *   --command-palette-row-h, --command-palette-row-px, --command-palette-row-py,
 *   --command-palette-input-py, --command-palette-input-px,
 *   --command-palette-list-p,
 *   --command-palette-heading-size, --command-palette-prefix-size, --command-palette-text-size
 *
 * Tone tokens (item left bar + icon tint) read from semantic theme tokens.
 */
@layer components {
  /*
   * Default component-token values are consumed via var() fallback (not declared
   * on the slot) so an ancestor-scoped override reaches them. Defaults: --command-palette-bg →
   * var(--background); --command-palette-fg → var(--foreground); --command-palette-border → var(--border);
   * --command-palette-border-soft → color-mix(in oklab, var(--border) 60%, transparent);
   * --command-palette-muted → var(--muted-foreground); --command-palette-prefix-content → ">";
   * --command-palette-tone-nav → var(--info); --command-palette-tone-action → var(--success);
   * --command-palette-tone-settings → var(--warning); --command-palette-tone-destructive → var(--error);
   * --command-palette-tone-ai → var(--accent). The [data-frame="terminal"] prefix override below still wins.
   */
  [data-slot="command-palette-content"] {
    position: relative;
    background: var(--command-palette-bg, var(--background));
    color: var(--command-palette-fg, var(--foreground));
  }

  /* Density: compact (default) */
  [data-slot="command-palette-content"][data-density="compact"] {
    --command-palette-row-h: 32px;
    --command-palette-row-px: 12px;
    --command-palette-row-py: 8px;
    --command-palette-input-py: 12px;
    --command-palette-input-px: 16px;
    --command-palette-list-p: 6px;
    --command-palette-heading-size: 12px;
    --command-palette-prefix-size: 14px;
    --command-palette-text-size: 14px;
  }

  /* Density: comfortable */
  [data-slot="command-palette-content"][data-density="comfortable"] {
    --command-palette-row-h: 40px;
    --command-palette-row-px: 12px;
    --command-palette-row-py: 10px;
    --command-palette-input-py: 16px;
    --command-palette-input-px: 20px;
    --command-palette-list-p: 8px;
    --command-palette-heading-size: 12px;
    --command-palette-prefix-size: 15px;
    --command-palette-text-size: 14px;
  }

  /* Density: dense */
  [data-slot="command-palette-content"][data-density="dense"] {
    --command-palette-row-h: 24px;
    --command-palette-row-px: 8px;
    --command-palette-row-py: 3px;
    --command-palette-input-py: 8px;
    --command-palette-input-px: 12px;
    --command-palette-list-p: 4px;
    --command-palette-heading-size: 11px;
    --command-palette-prefix-size: 13px;
    --command-palette-text-size: 13px;
  }

  /* Frame: border (default) — single 1px hairline. */
  [data-slot="command-palette-content"][data-frame="border"] {
    border: 1px solid var(--command-palette-border, var(--border));
    box-shadow: 0 20px 60px oklch(0% 0 0 / 0.6);
  }

  /* Frame: viewfinder — no border, four corner brackets. */
  [data-slot="command-palette-content"][data-frame="viewfinder"] {
    border: 0;
    box-shadow: 0 20px 60px oklch(0% 0 0 / 0.6);
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"]::before,
  [data-slot="command-palette-content"][data-frame="viewfinder"]::after,
  [data-slot="command-palette-content"][data-frame="viewfinder"] > .cp-corners::before,
  [data-slot="command-palette-content"][data-frame="viewfinder"] > .cp-corners::after {
    content: "";
    position: absolute;
    width: 18px;
    height: 18px;
    border: 0 solid var(--command-palette-fg, var(--foreground));
    pointer-events: none;
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"]::before {
    top: -1px;
    left: -1px;
    border-top-width: 2px;
    border-left-width: 2px;
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"]::after {
    top: -1px;
    right: -1px;
    border-top-width: 2px;
    border-right-width: 2px;
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"] > .cp-corners::before {
    bottom: -1px;
    left: -1px;
    border-bottom-width: 2px;
    border-left-width: 2px;
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"] > .cp-corners::after {
    bottom: -1px;
    right: -1px;
    border-bottom-width: 2px;
    border-right-width: 2px;
  }

  /* Frame: terminal — top + bottom 2px rules, no side borders. */
  [data-slot="command-palette-content"][data-frame="terminal"] {
    border: 0;
    border-top: 2px solid var(--command-palette-fg, var(--foreground));
    border-bottom: 2px solid var(--command-palette-fg, var(--foreground));
    box-shadow: 0 20px 60px oklch(0% 0 0 / 0.6);
    --command-palette-prefix-content: "$";
  }

  [data-slot="command-palette-content"][data-frame="terminal"]
    [data-slot="command-palette-input-prefix"] {
    color: var(--command-palette-fg, var(--foreground));
    font-weight: 700;
  }

  /* Frame: card — Linear-ish rounded shell with a subtle gradient surface. */
  [data-slot="command-palette-content"][data-frame="card"] {
    border: 1px solid var(--command-palette-border, var(--border));
    border-radius: 8px;
    background: linear-gradient(
      140deg,
      color-mix(
          in oklab,
          var(--command-palette-fg, var(--foreground)) 6%,
          var(--command-palette-bg, var(--background))
        )
        0%,
      var(--command-palette-bg, var(--background)) 100%
    );
    box-shadow: 0 30px 80px oklch(0% 0 0 / 0.7);
    overflow: hidden;
  }

  /* Frame: none — bare. */
  [data-slot="command-palette-content"][data-frame="none"] {
    border: 0;
    box-shadow: 0 20px 60px oklch(0% 0 0 / 0.6);
  }

  /* Input row */
  [data-slot="command-palette-input"] {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: var(--command-palette-input-py) var(--command-palette-input-px);
    border-bottom: 1px solid
      var(--command-palette-border-soft, color-mix(in oklab, var(--border) 60%, transparent));
  }

  [data-slot="command-palette-input-prefix"] {
    color: var(--command-palette-muted, var(--muted-foreground));
    font-size: var(--command-palette-prefix-size);
    user-select: none;
    flex-shrink: 0;
  }

  [data-slot="command-palette-input-prefix"][data-default]::before {
    content: var(--command-palette-prefix-content, ">");
  }

  [data-slot="command-palette-input-suffix"] {
    display: inline-flex;
    align-items: center;
    flex-shrink: 0;
  }

  /* List */
  [data-slot="command-palette-list"] {
    padding: var(--command-palette-list-p);
  }

  /* Group */
  [data-slot="command-palette-group-heading"] {
    padding: 8px 10px 4px;
    font-size: var(--command-palette-heading-size);
    font-weight: 500;
    color: var(--command-palette-muted, var(--muted-foreground));
  }

  /* Frame-scoped heading typography. Mirrors V2/V3 in the variants preview. */
  [data-slot="command-palette-content"][data-frame="viewfinder"]
    [data-slot="command-palette-group-heading"] {
    text-transform: uppercase;
    letter-spacing: 0.06em;
    font-size: 11px;
  }

  [data-slot="command-palette-content"][data-frame="terminal"]
    [data-slot="command-palette-group-heading"] {
    padding: 6px var(--command-palette-input-px) 2px;
    font-weight: 400;
  }

  /* Item */
  [data-slot="command-palette-item"] {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: var(--command-palette-row-py) var(--command-palette-row-px);
    min-height: var(--command-palette-row-h);
    font-size: var(--command-palette-text-size);
    color: var(--command-palette-fg, var(--foreground));
    cursor: pointer;
    user-select: none;
    position: relative;
  }

  [data-slot="command-palette-item"][aria-disabled="true"] {
    opacity: 0.5;
    cursor: not-allowed;
  }

  [data-slot="command-palette-item"][aria-selected="true"] {
    background: color-mix(in oklab, var(--command-palette-fg, var(--foreground)) 7%, transparent);
    color: var(--command-palette-fg, var(--foreground));
  }

  /* Viewfinder frame replaces the selection tint with a 2px left accent bar
     (matches the dialog viewfinder language). Use ::after so it doesn't
     collide with the tone bar at [data-tone]:not([data-tone="neutral"])::before. */
  [data-slot="command-palette-content"][data-frame="viewfinder"]
    [data-slot="command-palette-item"][aria-selected="true"] {
    background: transparent;
    font-weight: 500;
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"]
    [data-slot="command-palette-item"][aria-selected="true"]::after {
    content: "";
    position: absolute;
    left: 0;
    top: 4px;
    bottom: 4px;
    width: 2px;
    background: var(--command-palette-fg, var(--foreground));
    pointer-events: none;
  }

  /* Terminal frame inverts selection (white-on-black). */
  [data-slot="command-palette-content"][data-frame="terminal"]
    [data-slot="command-palette-item"][aria-selected="true"] {
    background: var(--command-palette-fg, var(--foreground));
    color: var(--command-palette-bg, var(--background));
    font-weight: 500;
  }

  /* Card frame: rows float inside the list padding with a rounded selection. */
  [data-slot="command-palette-content"][data-frame="card"] [data-slot="command-palette-item"] {
    margin: 0 var(--command-palette-list-p);
    border-radius: 6px;
  }

  [data-slot="command-palette-content"][data-frame="card"]
    [data-slot="command-palette-item"][aria-selected="true"] {
    background: color-mix(in oklab, var(--command-palette-fg, var(--foreground)) 8%, transparent);
  }

  [data-slot="command-palette-item-icon"] {
    display: inline-flex;
    align-items: center;
    color: var(--command-palette-muted, var(--muted-foreground));
    flex-shrink: 0;
  }

  [data-slot="command-palette-item-label"] {
    flex: 1 1 auto;
    min-width: 0;
  }

  [data-slot="command-palette-item-shortcut"] {
    color: var(--command-palette-muted, var(--muted-foreground));
    font-size: 11px;
    flex-shrink: 0;
  }

  /* Tones: 2px left bar + icon tint. Label color inherits to preserve readability. */
  [data-slot="command-palette-item"][data-tone]:not([data-tone="neutral"])::before {
    content: "";
    position: absolute;
    left: 4px;
    top: 8px;
    bottom: 8px;
    width: 2px;
  }

  [data-slot="command-palette-item"][data-tone="nav"]::before {
    background: var(--command-palette-tone-nav, var(--info));
  }
  [data-slot="command-palette-item"][data-tone="action"]::before {
    background: var(--command-palette-tone-action, var(--success));
  }
  [data-slot="command-palette-item"][data-tone="settings"]::before {
    background: var(--command-palette-tone-settings, var(--warning));
  }
  [data-slot="command-palette-item"][data-tone="destructive"]::before {
    background: var(--command-palette-tone-destructive, var(--error));
  }
  [data-slot="command-palette-item"][data-tone="ai"]::before {
    background: var(--command-palette-tone-ai, var(--accent));
  }

  /* Hide the tone bar on disabled rows; the muted row body already signals state. */
  [data-slot="command-palette-item"][aria-disabled="true"]::before {
    display: none;
  }

  [data-slot="command-palette-item"][data-tone="nav"] [data-slot="command-palette-item-icon"] {
    color: var(--command-palette-tone-nav, var(--info));
  }
  [data-slot="command-palette-item"][data-tone="action"] [data-slot="command-palette-item-icon"] {
    color: var(--command-palette-tone-action, var(--success));
  }
  [data-slot="command-palette-item"][data-tone="settings"] [data-slot="command-palette-item-icon"] {
    color: var(--command-palette-tone-settings, var(--warning));
  }
  [data-slot="command-palette-item"][data-tone="destructive"]
    [data-slot="command-palette-item-icon"] {
    color: var(--command-palette-tone-destructive, var(--error));
  }
  [data-slot="command-palette-item"][data-tone="ai"] [data-slot="command-palette-item-icon"] {
    color: var(--command-palette-tone-ai, var(--accent));
  }

  /* Under the terminal frame's inverted selection (bg: --command-palette-fg, color: --command-palette-bg)
     tones lose contrast: in the dark-mode minimal theme several tone tokens
     resolve to the same color as --foreground (e.g. --success → --base-success
     → #e5e5e5 = white), which would render the 2px bar and icon invisible
     against the white selection background. Re-tint both to --command-palette-bg so they
     remain visible without re-coloring the label. */
  [data-slot="command-palette-content"][data-frame="terminal"]
    [data-slot="command-palette-item"][aria-selected="true"]
    [data-slot="command-palette-item-icon"] {
    color: var(--command-palette-bg, var(--background));
  }

  [data-slot="command-palette-content"][data-frame="terminal"]
    [data-slot="command-palette-item"][aria-selected="true"][data-tone]:not(
      [data-tone="neutral"]
    )::before {
    background: var(--command-palette-bg, var(--background));
  }

  /* Match highlight */
  [data-slot="command-palette-item-match"] {
    color: var(--command-palette-fg, var(--foreground));
    background: transparent;
    font-weight: 600;
    text-decoration: underline;
    text-underline-offset: 2px;
    text-decoration-thickness: 1px;
  }

  /* Empty state */
  [data-slot="command-palette-empty"] {
    padding: 24px 12px;
    text-align: center;
    font-size: var(--command-palette-text-size);
    color: var(--command-palette-muted, var(--muted-foreground));
  }

  /* Footer */
  [data-slot="command-palette-footer"] {
    display: flex;
    align-items: center;
    gap: 16px;
    flex-wrap: wrap;
    padding: 8px 12px;
    border-top: 1px solid
      var(--command-palette-border-soft, color-mix(in oklab, var(--border) 60%, transparent));
    font-size: 11px;
    color: var(--command-palette-muted, var(--muted-foreground));
    user-select: none;
  }

  [data-slot="command-palette-content"][data-frame="card"] [data-slot="command-palette-footer"] {
    background: color-mix(in oklab, black 25%, transparent);
    border-top: 1px solid
      color-mix(in oklab, var(--command-palette-fg, var(--foreground)) 8%, transparent);
  }
}

@media (forced-colors: active) {
  [data-slot="command-palette-content"][data-frame="border"],
  [data-slot="command-palette-content"][data-frame="terminal"],
  [data-slot="command-palette-content"][data-frame="card"] {
    border-color: CanvasText;
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"]::before,
  [data-slot="command-palette-content"][data-frame="viewfinder"]::after,
  [data-slot="command-palette-content"][data-frame="viewfinder"] > .cp-corners::before,
  [data-slot="command-palette-content"][data-frame="viewfinder"] > .cp-corners::after {
    border-color: CanvasText;
  }
}
